package main

import "fmt"

func main() {
    // Create an array that holds exactly 3 strings
    var colors [3]string

    // Arrays are 0-indexed!
    colors[0] = "Red"
    colors[1] = "Green"
    colors[2] = "Blue"

    // If we tried colors[3] = "Yellow", the program would crash!

    fmt.Println(colors)
}
